cd /work && cat > /tmp/verify.c << 'EOF'
#include <stdio.h>

int main() {
    int a = 11;
    printf("a = %d\n", a);
    printf("-a = %d (negation)\n", -a);
    printf("~a = %d (bitwise NOT)\n", ~a);
    return 0;
}
EOF
gcc /tmp/verify.c -o /tmp/verify && /tmp/verify

cd /work && cat > /tmp/test_fix.c << 'EOF'
#include <stdio.h>

int main() {
    // Test cases from bitwise.be
    int a = 11;

    printf("Test: ~a == -12\n");
    printf("  a = %d\n", a);
    printf("  ~a = %d\n", ~a);
    printf("  Expected: -12\n");
    printf("  Match: %s\n\n", (~a == -12) ? "true" : "false");

    printf("Test: ~11 == -12\n");
    printf("  ~11 = %d\n", ~11);
    printf("  Expected: -12\n");
    printf("  Match: %s\n", (~11 == -12) ? "true" : "false");

    return 0;
}
EOF
gcc /tmp/test_fix.c -o /tmp/test_fix && /tmp/test_fix
